"use strict";(self.webpackChunkotavia_docs=self.webpackChunkotavia_docs||[]).push([["266"],{6164(e){e.exports=JSON.parse('{"version":{"pluginId":"default","version":"current","label":"Next","banner":null,"badge":false,"noIndex":false,"className":"docs-version-current","isLast":true,"docsSidebars":{"docsSidebar":[{"type":"link","href":"/docs/intro","label":"Introduction","docId":"intro","unlisted":false},{"type":"link","href":"/docs/quick_start","label":"Quick Start","docId":"quick_start","unlisted":false},{"type":"link","href":"/docs/core_concept","label":"Core Concepts and Design","docId":"core_concept","unlisted":false},{"type":"category","label":"Guide","collapsed":false,"items":[{"type":"link","href":"/docs/guide/actor_model","label":"Actor Model","docId":"guide/actor_model","unlisted":false},{"type":"link","href":"/docs/guide/message_model","label":"Message Model","docId":"guide/message_model","unlisted":false},{"type":"link","href":"/docs/guide/stack_model","label":"Stack Execution Model","docId":"guide/stack_model","unlisted":false},{"type":"link","href":"/docs/guide/channel_pipeline","label":"Channel Pipeline","docId":"guide/channel_pipeline","unlisted":false},{"type":"link","href":"/docs/guide/io_model","label":"IO Model","docId":"guide/io_model","unlisted":false},{"type":"link","href":"/docs/guide/reactor_model","label":"Reactor Model","docId":"guide/reactor_model","unlisted":false},{"type":"link","href":"/docs/guide/threading_model","label":"Threading Model","docId":"guide/threading_model","unlisted":false},{"type":"link","href":"/docs/guide/address_model","label":"Address Model","docId":"guide/address_model","unlisted":false},{"type":"link","href":"/docs/guide/ioc","label":"Actor IOC","docId":"guide/ioc","unlisted":false},{"type":"link","href":"/docs/guide/serde","label":"Serde Framework","docId":"guide/serde","unlisted":false},{"type":"link","href":"/docs/guide/slf4a","label":"SLF4A","docId":"guide/slf4a","unlisted":false}],"collapsible":true},{"type":"category","label":"Modules","items":[{"type":"link","href":"/docs/module/","label":"Modules","docId":"module/index","unlisted":false},{"type":"link","href":"/docs/module/buffer","label":"Buffer","docId":"module/buffer","unlisted":false}],"collapsed":true,"collapsible":true}]},"docs":{"core_concept":{"id":"core_concept","title":"Core Concepts and Design","description":"Challenges of existing programming paradigms","sidebar":"docsSidebar"},"guide/actor_model":{"id":"guide/actor_model","title":"Actor Model","description":"Actor Hierarchy","sidebar":"docsSidebar"},"guide/address_model":{"id":"guide/address_model","title":"Address Model","description":"Actors are isolated from each other and can only communicate through Address instances. The Address model provides compile-time type safety and flexible routing strategies.","sidebar":"docsSidebar"},"guide/channel_pipeline":{"id":"guide/channel_pipeline","title":"Channel Pipeline","description":"The ChannelPipeline is the core processing chain for channel data in otavia. It is fundamentally similar to Netty\'s ChannelPipeline but with important differences in how it integrates with the Actor model.","sidebar":"docsSidebar"},"guide/io_model":{"id":"guide/io_model","title":"IO Model","description":"The otavia IO model is a layered, actor-integrated IO framework inspired by Netty but re-architected around the Actor model. Each ActorThread owns its own IoHandler (with a dedicated NIO Selector) and runs both IO and actor logic in a time-sliced loop.","sidebar":"docsSidebar"},"guide/ioc":{"id":"guide/ioc","title":"Actor IOC","description":"Otavia provides compile-time type-safe dependency injection for Actor addresses using Scala 3\'s match types. The ActorSystem acts as the IoC container, and BeanManager handles registration and lookup.","sidebar":"docsSidebar"},"guide/message_model":{"id":"guide/message_model","title":"Message Model","description":"Messages are special objects used by Actors for communication. It is recommended to define them as case classes.","sidebar":"docsSidebar"},"guide/reactor_model":{"id":"guide/reactor_model","title":"Reactor Model","description":"In otavia, each ActorThread owns an IoHandler (for NIO, this is a NioHandler wrapping a Java NIO Selector) and runs a three-phase loop: IO select/process, IO pipeline (ChannelsActors), and business logic (StateActors). The IO layer is transparent to most users \u2014 ChannelsActor encapsulates all IO interactions.","sidebar":"docsSidebar"},"guide/serde":{"id":"guide/serde","title":"Serde Framework","description":"Serde is a generic serialization and deserialization framework for otavia based on Buffer. It provides a unified interface for all serialization tools, designed to work efficiently with otavia\'s buffer management system.","sidebar":"docsSidebar"},"guide/slf4a":{"id":"guide/slf4a","title":"SLF4A","description":"SLF4A is the logging standard in otavia, referencing the design of SLF4J. It provides an asynchronous logging framework that integrates with the Actor system.","sidebar":"docsSidebar"},"guide/stack_model":{"id":"guide/stack_model","title":"Stack Execution Model","description":"The Stack is otavia\'s most distinctive innovation. It replaces traditional callbacks and coroutines with a manually managed state machine using pooled objects.","sidebar":"docsSidebar"},"guide/threading_model":{"id":"guide/threading_model","title":"Threading Model","description":"otavia uses an ActorThread-per-CPU model. Each ActorThread is an independent OS thread running its own event loop, with dedicated buffer pools and scheduling queues.","sidebar":"docsSidebar"},"intro":{"id":"intro","title":"Introduction","description":"GitHub","sidebar":"docsSidebar"},"module/buffer":{"id":"module/buffer","title":"Buffer","description":"This document introduce the buffer modules of otavia.","sidebar":"docsSidebar"},"module/index":{"id":"module/index","title":"Modules","description":"This document introduce the core modules of otavia.","sidebar":"docsSidebar"},"name_from":{"id":"name_from","title":"Name From","description":"Why is it called otavia?"},"quick_start":{"id":"quick_start","title":"Quick Start","description":"Environment","sidebar":"docsSidebar"}}}}')}}]);